mapper.insert:
/*
     SQL ID : FileBoxInfoDAO.insertFileBox
     설  명 : 파일함 폴더(파일) 등록
*/
INSERT INTO TB_LMS_ATFL_BOX (
       ATFL_BOX_ID
     , UP_ATFL_BOX_ID
     , ATFL_BOX_TYCD
     , FILE_ID
     , ATFL_BOXNM
     , RGTR_ID
     , REG_DTTM
     , MDFR_ID
     , MOD_DTTM
) VALUES (
       #{fileBoxCd}
     , #{parFileBoxCd, javaType=String}
     , #{fileBoxTypeCd}
     , #{fileSn, javaType=String}
     , #{fileBoxNm}
     , #{rgtrId}
     , FN_DTTM()
     , #{rgtrId}
     , FN_DTTM()
)

