mapper.select:
        /*
             SQL ID : FileBoxInfoDAO.listDeleteFileBox
             설  명 : 삭제할 파일박스 목록 조회
         */


        SELECT ATFL_BOX_ID
		FROM TB_LMS_ATFL_BOX
		WHERE RGTR_ID = #{mdfrId}
		START WITH ATFL_BOX_ID = #{fileBoxCd}
		CONNECT BY PRIOR ATFL_BOX_ID = UP_ATFL_BOX_ID

mapper.update:
/*
     SQL ID : FileBoxInfoDAO.updateFileBoxNm
     설  명 : 파일함의 폴더명 변경
 */
UPDATE TB_LMS_ATFL_BOX
   SET ATFL_BOXNM = #{fileBoxNm}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE ATFL_BOX_ID = #{fileBoxCd}
   AND RGTR_ID = #{mdfrId}

mapper.select:
/*
     SQL ID : FileBoxInfoDAO.countUserFileBoxCd
     설  명 : 자신의 파일함 여부 카운트
 */
SELECT COUNT(1) AS CNT
  FROM TB_LMS_ATFL_BOX
 WHERE ATFL_BOX_ID = #{fileBoxCd}
   AND RGTR_ID = #{rgtrId}

   AND ATFL_BOX_TYCD = #{fileBoxTypeCd}

/* SQL ID : FileBoxInfoDAO.listFileBoxFileInfo 설 명 : 자신의 파일함 파일정보 목록 */ SELECT A.FILENM , A.FILE_SAVENM , A.FILE_SIZE , A.FILE_PATH , A.FILE_ID , A.ATFL_REPO_PATH FROM TB_LMS_ATFL A JOIN TB_LMS_ATFL_BOX B ON A.FILE_ID = B.FILE_ID AND B.RGTR_ID = #{rgtrId} AND B.ATFL_BOX_ID IN (
#{item}
) WHERE A.ATFL_REPO_ID = 'FILE_BOX' AND A.ORG_ID = #{orgId}

    	/*
             SQL ID : FileBoxInfoDAO.selectFileBox
             설  명 : 파일박스 정보 가져오기
         */
		SELECT
		 	  A.ATFL_BOX_ID
			, A.UP_ATFL_BOX_ID
			, A.FILE_ID
			, A.ATFL_BOX_TYCD
			, A.ATFL_BOXNM
			, A.RGTR_ID
			, A.REG_DTTM
			, A.MDFR_ID
			, A.MOD_DTTM
		FROM TB_LMS_ATFL_BOX A
		WHERE A.RGTR_ID = #{rgtrId}

			AND A.UP_ATFL_BOX_ID = #{parFileBoxCd}


			AND A.ATFL_BOX_TYCD = #{fileBoxTypeCd}


			AND A.ATFL_BOX_ID = #{fileBoxCd}


			AND A.ATFL_BOXNM = #{fileBoxNm}
